var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무사 귀환을 축하드립니다.","JPN":"無事帰還できてよかったです。","ENG":"Congratulations on your safe return.","TWN":"恭喜安全回歸。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마지막 그림자형 침식체를 놓친 건 아쉽지만 이것만으로도 큰 성과라고 할 수 있겠죠.","JPN":"最後のシャドウ型侵食体を取り逃がしたのは残念ですが、これだけでも大いなる成果と言えるでしょう。","ENG":"Although it's regrettable that we lost the final Shadow-type C.O., I think we've achieved considerable success.","TWN":"雖然最後讓暗影型侵蝕體溜掉了有些可惜，但仍算是大獲成功了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"3종 침식체 한 마리도 상대를 못해서 쩔쩔매던 게 엊그제 같은데 말입니다.","JPN":"第3種侵食体1匹相手に手こずっていたのが昨日のことのようですが。","ENG":"I mean, it wasn't so long ago that we couldn't even face off a single Category 3.","TWN":"以前可是連一隻3類侵蝕體都對付不了呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히 스승님이 돌아오신 후로 회사의 사정이 점점 좋아지고 있는 것 같아 흐뭇하군요.","JPN":"師匠が戻られてから、会社の業績も徐々に安定してきて微笑ましいですね。","ENG":"The company seems to be getting back on its feet ever since the Master's return.","TWN":"自從老師回來之後，公司的情況越來越好了，我真的很高興。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모두들 수고하셨습니다.","JPN":"みなさん、お疲れ様でした。","ENG":"Good work, everyone.","TWN":"各位辛苦了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 정도야 별거 아니지! 다음에도 기대하라고!","JPN":"この程度の仕事なら簡単だ！　次も期待していいぞ！","ENG":"Aw, that was a piece of cake! You can count on me again!","TWN":"這不算什麼啦！期待我下一次的表現吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래. 앞으로도 미끼 역할은 쭉~ 너니까 기대할게.","JPN":"そうね。これからもエサ役はずーっとあんただからそこは期待する。","ENG":"Yeah. I'll be counting on you to be the bait again.","TWN":"好，那以後你就專門負責當誘餌，我會期待你的表現的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 이 자식아? 지금 뭐라고 했어!","JPN":"ああん？　お前、もう一回言ってみろ！","ENG":"What? You jerk! What did you just say?","TWN":"什麼？你這傢伙？你剛說什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"네 입으로 다음에도 기대하라며?","JPN":"自分の口から次も期待してって言ったでしょ？","ENG":"You're the one who said we could count on you.","TWN":"不是你自己說讓我期待的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"왜, 기대하지 마?","JPN":"期待しない方がいいの？","ENG":"Should we not count on you then?","TWN":"怎麼，不用期待了？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아, 아니 그건 아니고, 기대하라는 건 맞는데......","JPN":"いや、それは違うけど。期待していいけど……","ENG":"Y-yes, but that's not what I meant...","TWN":"不、不是，當然要期待……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"왜 이렇게 기분이 찝찝하지?","JPN":"なんだかスッキリしないな。","ENG":"Why do I feel like I've been duped?","TWN":"不過，怎麼感覺怪怪的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장...... 계좌 확인해 봤어?","JPN":"た、隊長……残高は確認した？","ENG":"C-Cap... Did you check the bank account?","TWN":"隊、隊長……你查看帳戶了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"정식 라이선스 소대가 돼서 그런지 작전 수당도 늘어났나 봐.","JPN":"正式ライセンス小隊になったおかげで、作戦手当も増えたみたい。","ENG":"They must have given us a raise for our mission bonus, now that we're an officially licensed squad.","TWN":"不知道是不是因為成為正式小隊的關係，作戰補貼好像變多了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후훗, 이번엔 관리국의 긴급 지원 요청까지 해결했잖아?","JPN":"ふふ、今回は管理局の緊急応援要請まで解決したからね。","ENG":"Hah hah, we even took care of the Administration's request for emergency support this time.","TWN":"嘻嘻，這次還處理了管理局的緊急支援請求。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아마 3종 침식체 격파에 따른 추가 지원금도 같이 들어왔을 거야.","JPN":"たぶん第3種侵食体撃破による追加補助金も振り込まれたと思うわ。","ENG":"I bet we got an extra bonus for taking down the Category 3.","TWN":"應該還包括了消滅3類侵蝕體的額外支援金。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"응. 이 정도면 당분간 생활비 걱정은 안 해도 될 것 같아.","JPN":"うん。これくらいあれば、しばらく生活費の心配はないかな。","ENG":"Great. We shouldn't have to worry about paying the bills for a while now.","TWN":"嗯。有了這些錢，暫時不用擔心生活費了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"장보러 가자! 오늘은 특식이야!","JPN":"買い出しに行こう！　今日はフルコースを振る舞うね！","ENG":"Let's go grocery shopping! I'm making you something special today!","TWN":"我們去買東西吧！今天吃大餐！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 오늘은 얌전하게 굴었으니까 간식을 두 배로 달래.","JPN":"オルカが今日は大人しくしたから、おやつは2倍ほしいって。","ENG":"Orca says she wants double the amount of snacks for being good today.","TWN":"奧爾卡說自己今天很乖，得給她雙倍零食。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그게...... 곤란해.","JPN":"それは……困るわね。","ENG":"Well... I'm afraid we can't.","TWN":"那個……不行。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"저번 작전 때 그 녀석이 부셔 먹은 장갑차 수리비도 아직 다 못 갚았거든.","JPN":"前の作戦の時にあの子がぶっ壊した装甲車の修理代もまだ返してないのよ。","ENG":"We still haven't paid off the repair costs for the APC she smashed in the last mission.","TWN":"上次作戰的時候那個傢伙弄壞的裝甲車修理費還沒繳清呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이대로라면 다음주까지 간식은 절반밖에 못 줄 것 같은데.","JPN":"このままだと、来週までおやつも半分くらいしかあげられないわ。","ENG":"At this rate, we can only give you half portions of snacks till next week.","TWN":"所以到下週為止，只能給一半零食。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......정말?","JPN":"……本当に？","ENG":"Really?","TWN":"……真的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"정말.","JPN":"本当。","ENG":"Really.","TWN":"真的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카! 맘에 안 든다고 냉장고 걷어차는 거 누구에게 배웠어?!","JPN":"オルカ！　気に食わないからって冷蔵庫を蹴るのはやめなさい！","ENG":"Orca! Who taught you to kick the fridge just because you're upset?","TWN":"奧爾卡！不要因為心情不好就踢冰箱，這都是跟誰學的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"찰리, 오르카 좀 말려!","JPN":"チャーリー、オルカを止めて！","ENG":"Charlie, stop her!","TWN":"查理，你去勸勸奧爾卡！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"참아, 오르카! 여기서 빚이 더 늘어나면 정말 곤란하다고!","JPN":"落ち着けよ、オルカ！　これ以上借金は増やしたくないんだよ！","ENG":"Take it easy, Orca! We really can't afford to get into any further debt!","TWN":"冷靜，奧爾卡！你這樣只會讓負債變得更多，到時候就真麻煩了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미나야, 우리 소대는 오늘 특식인데 너흰 어때?","JPN":"ミナ、うちの小隊は今日フルコースだけど、そっちはどう？","ENG":"Hey, Mina. We're going to grab something special to eat tonight. How about you guys?","TWN":"米娜，我們小隊今天吃大餐，你們呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 우린 별다른 일정 없는데?","JPN":"うん？　特に予定はないよ。","ENG":"Hm? We don't have anything special planned.","TWN":"啊？我們沒有別的安排吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"삭막하네, 펜릴 소대는.","JPN":"寂しいな、フェンリル小隊は。","ENG":"Jeez, you guys keep it real dry at Fenrir, don't you?","TWN":"你們芬里爾小隊真是無趣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어때, 너도 같이 먹으러 갈래?","JPN":"私たちと一緒に食べない？","ENG":"Care to join us?","TWN":"那你要不要跟我們一起去吃？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......우리가 그럴 만큼 친한 사이였어?","JPN":"……一緒に食事するほどの仲だったっけ？","ENG":"Since when were we so close?","TWN":"……我們好像沒那麼熟吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐 어때. 친구는 가까이, 적은 더 가까이 두라는 말도 있잖아.","JPN":"いいじゃない。「友は近くに置いておけ、しかし敵はもっと近くに置け」という名言もあるでしょ。","ENG":"Who cares. You know what they say. Keep your friends close, but your enemies closer.","TWN":"沒關係啊。不是有句話這麼說『要親近朋友，更要親近你的敵人。』"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 그거. 결국 적이라는 말이잖아......","JPN":"なにそれ。結局敵ってことじゃない……","ENG":"What the heck is that. You're basically saying I'm your enemy...","TWN":"什麼嘛，你的意思是我們是敵人……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래. 식비 아끼는 셈 치고 가지, 뭐.","JPN":"いいや。食費の節約になりそうだから行く。","ENG":"Fine. I might as well join you. If anything it'll save me some money.","TWN":"好吧，就當節省伙食費了，我去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠시만요, 미나 양.","JPN":"お待ちください、ミナさん。","ENG":"One moment, Mina.","TWN":"等等，米娜小姐。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 해산하지 말고 기다리세요. 할 얘기가 있습니다.","JPN":"ミナさんには話があるので、解散せず待機してください。","ENG":"Please stand by for now. I have something to tell you.","TWN":"米娜小姐等一下，我有話要跟你說。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 그러고 보니......","JPN":"あ、そうだった……","ENG":"Oh, that's right...","TWN":"啊，我差點忘了……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐야? 무슨 일인데 부사장님이 너만 남으라는 거야?","JPN":"なになに？　副社長と個人面談なの？","ENG":"What? Why's the Vice President asking you to stay behind?","TWN":"怎麼了？為什麼副總讓你單獨留下來？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잘은 몰라. 선배가 무슨 일이 있는 것 같다고 하긴 했는데.","JPN":"よくわからない。先輩からなんか話があるって聞いてはいるけどね。","ENG":"I'm not sure. I think Shiyoon did say something was up though.","TWN":"不太清楚。前輩之前說過好像有什麼事情。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음, 너도 참 먹을 복이 없네.","JPN":"ふーん、コハルのフルコースが待っているのに残念だね。","ENG":"Well, tough luck to you. No free dinner tonight then.","TWN":"哎，你可真是沒有口福啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님이 부르시면 어쩔 수 없지. 다음 기회에 봐.","JPN":"副社長の呼び出しなら仕方ない。また今度にしよう。","ENG":"If the Vice President wants you to stay, what can you do? Maybe next time.","TWN":"既然是副總找你有事，就沒辦法了。下次再約吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 마침 한 명 더 있네.","JPN":"あ、ちょうどもう一人いた。","ENG":"Oh, there's another person we can invite.","TWN":"咦，還有一個人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"거기! 오르카라고 했었지?","JPN":"ねえ！　オルカって言ったよね？","ENG":"You over there! You're Orca, right?","TWN":"喂！你叫奧爾卡是吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"냉장고는 그만 걷어차고 언니들이랑 맛있는 거 먹으러 갈래?","JPN":"冷蔵庫に八つ当たりするのはやめて、お姉ちゃんたちと美味しいものでも食べにいかない？","ENG":"Why don't you stop kicking the fridge and come grab something tasty to eat with us?","TWN":"別再踢冰箱了，要不要跟姐姐們一起去吃好吃的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......쟤도 참 대단하다니까.","JPN":"……あの子もなかなかの性格だね。","ENG":"She's unbelievable...","TWN":"……她可真夠執著的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"긴 이야기는 아닙니다. 예전에 신청해둔 허가증이 이제야 나왔거든요.","JPN":"長い話ではありません。以前申請した許可証がやっと出たのです。","ENG":"I won't keep you for long. We just got the permit we requested a while back.","TWN":"是這樣，以前申請的許可證現在審批下來了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"허가증?","JPN":"許可証？","ENG":"What permit?","TWN":"許可證？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 내일부터 미나 양은 관리국 카운터 아카데미 고등부에 임시 편입됩니다.","JPN":"はい、明日からミナさんは管理局カウンターアカデミー高等部に臨時編入されます。","ENG":"Starting tomorrow, you'll be temporarily transferred to the Administration's Counter Academy as a high schooler.","TWN":"對。明天開始將臨時被編入管理局制裁者學院-高等部。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"학교 생활에 적응할 시간이 필요할 테니 당분간 출근은 하지 않아도 괜찮습니다.","JPN":"学校生活に慣れるまで時間が必要でしょうから、しばらく出勤しなくても大丈夫です。","ENG":"Since you'll need some time to acclimate to student life, you're excused from work for the time being.","TWN":"我想你需要一些時間適應學校生活。所以暫時不用上班了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 그게 다 무슨 소리야?","JPN":"ま、待って！　何を言っているの？","ENG":"W-wait! What are you talking about?","TWN":"等、等等！你說的是什麼意思？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 편입 신청 같은 거 한 적 없어!","JPN":"私は編入申請なんかしてないよ！","ENG":"I never asked to be transferred!","TWN":"我可從來沒有提交過入學申請啊！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알고 있습니다. 이건 미나 양이 아니라 사장님께서 신청하신 거에요.","JPN":"承知しています。申請したのはミナさんではなく、社長です。","ENG":"I'm quite aware. This was actually the Boss's request.","TWN":"我知道。不是你，是老闆幫你申請的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님이?","JPN":"社長が？","ENG":"The Boss?","TWN":"老闆？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 미나 양은 불미스러운 사고 때문에 현재 고교 중퇴인 상황이죠.","JPN":"はい。ミナさんは不慮の事故によって高校を中退していますね。","ENG":"That's right. We understand you had to drop out of high school due to an unfortunate incident.","TWN":"是啊。我記得你因為一些事情，現在是高中退學狀態。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 고등학교 졸업장 정도는 받아 두는 게 장래를 위해서도 좋을 거라고 하시더군요.","JPN":"社長曰く、将来のために高等学校卒業証明書ぐらいはもっておいたほうがいいと。","ENG":"But the Boss figured you should at least get a high school diploma for your future's sake.","TWN":"老闆說，為你的將來考慮，至少要拿到高中畢業證書。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 부담스럽다면 연수 지원이라고 생각해도 좋습니다.","JPN":"もし負担に感じるなら、社員への研修支援制度だと考えれば良いでしょう。","ENG":"If this feels awkward, just think of it as a company-sponsored seminar.","TWN":"如果你覺得有負擔的話，可以當成是進修。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"생각해 줘서 고맙긴 한데...... 그럼 회사는?","JPN":"配慮してくれたことはありがたいけど……仕事は？","ENG":"Well, I do appreciate the thoughtfulness... But what about work?","TWN":"感謝你們替我著想……可公司怎麼辦？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난...... 언니 병원비 때문에라도 계속 일해야 하는데......","JPN":"私は……姉の治療費のために働かなければならないの……","ENG":"I... I need to keep working to pay my sister's hospital bills...","TWN":"我……因為姐姐的住院費，不能不工作……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국이 세운 카운터 아카데미는 일반 학교와는 다릅니다.","JPN":"管理局が設立したカウンターアカデミーは一般学校とは異なります。","ENG":"The Administration's Counter Academy isn't like ordinary schools.","TWN":"管理局成立的制裁者學院與普通學校不一樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"필수 교과목만 이수하면 그 뒤에는 회사 일과 병행이 가능하죠.","JPN":"必須教科さえ履修すれば、その後は会社の仕事と並行することが可能です。","ENG":"As long as you fulfill the mandatory courses, you're authorized to continue working.","TWN":"只要學完必修課，就能學習與工作並行了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양처럼 용병 생활을 하다가 뒤늦게 편입하는 경우도 꽤 많습니다.","JPN":"ミナさんのように傭兵生活をしていて、後から編入するケースもかなり多いです。","ENG":"There are many those who have transferred late to the academy while working as a mercenary, like you.","TWN":"像米娜小姐這樣先成為傭兵後再入學的情況也有很多。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기본 수당은 계속 지급될 테니 걱정 마세요.","JPN":"基本手当は引き続き支給されるので心配しないでください。","ENG":"Don't worry. You'll still get your base pay.","TWN":"還有基礎工資也會一直發放，你不用擔心。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양이 끝까지 내키지 않는다면 취소해도 상관은 없습니다.","JPN":"ミナさんの気が進まないなら、手続きを取り消しても構いませんが。","ENG":"If you really feel uncomfortable, you're free to cancel the enrollment.","TWN":"如果你實在不願意，也可以取消。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 개인적으로는 그러지 말라고 하고 싶군요.","JPN":"でも個人的には提案を受け入れてもらいたいです。","ENG":"But personally, I would advise against that.","TWN":"但我個人希望你能去學校學習。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 여러 가지 사정 때문에 정상적인 학교 생활을 하지 못했어요.","JPN":"私はいろんな事情があって、正常な学校生活を送ることができませんでした。","ENG":"I for one never got to enjoy a normal school life for many reasons.","TWN":"我以前上學的時候因為一些原因沒能畢業。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후회는 없지만, 막상 나이가 들고 나니 아쉬움이 남더군요.","JPN":"後悔はありませんが、この歳になると惜しい気持ちがあります。","ENG":"Although I have no regrets, I can't help but wonder what it would've been like, now that I'm old.","TWN":"雖然不後悔，但年紀大了之後，還是覺得有些遺憾。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 아직 어립니다.","JPN":"ミナさんはまだ若いです。","ENG":"On the other hand, you're still young.","TWN":"米娜小姐你還年輕。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식체 사냥 따위는 앞으로 지겹게 하게 되겠죠.","JPN":"侵食体狩りなんて、この先飽きるほどできるでしょう。","ENG":"You'll have plenty of opportunities to hunt C.O.s; you'll get sick of it eventually.","TWN":"狩獵侵蝕體這種事，以後會多到讓你不耐煩。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 기회가 있을 때, 학교에서 친구들을 사귀는 것도 나쁜 경험은 아닐 겁니다.","JPN":"だからまだチャンスがあるうちに、学校で友達を作ったりするのも悪い経験ではないでしょう。","ENG":"So seizing the chance to study in school and make some friends won't be such a bad idea for now.","TWN":"所以趁這次機會，去學校交一些新朋友也不錯。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 아니, 내키지 않는 건 아냐.","JPN":"あ……いや、気が進まないわけじゃないの。","ENG":"Oh... Well, it's not that I don't want to.","TWN":"不……我，我不是不想去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그냥......","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학교를 다시 다닐 수 있을 거란 생각은...... 해 본 적 없었거든.","JPN":"また学校に通えると……考えたこともなかったから。","ENG":"I never thought... I could ever go back to school.","TWN":"我從來沒想過……可以繼續上學。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어째 좀...... 현실감이 안 나서.","JPN":"なんだか……ちょっと実感が湧かなくて。","ENG":"It just all feels... kind of surreal.","TWN":"感覺有些……不太真實。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 결정은?","JPN":"それで、答えは？","ENG":"So have you decided?","TWN":"那麼你的決定是？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 갈게.","JPN":"うん、行くよ。","ENG":"Yeah. I'll go.","TWN":"好吧，我去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님께도 고맙다고 전해 줬으면 좋겠어, 부사장님.","JPN":"社長にも感謝すると伝えてほしい、副社長。","ENG":"Please tell the Boss I said thank you.","TWN":"請你替我向老闆轉達謝意，副總。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};